if art.IsValid():
    if not art.HasAPI(PhysxSchema.PhysxArticulationAPI):
        PhysxSchema.PhysxArticulationAPI.Apply(art)
    fb = art.GetAttribute("physxArticulation:fixedBase")
    if not fb or not fb.IsValid():
        fb = art.CreateAttribute("physxArticulation:fixedBase", Sdf.ValueTypeNames.Bool)
    fb.Set(False)
    print(f"Carter fixedBase={fb.Get()}")

# Wheel colliders -> convexHull
count = 0
for prim in Usd.PrimRange(stage.GetPrimAtPath(robot_path)):
    name_lower = prim.GetName().lower()
    if any(k in name_lower for k in ("wheel","caster","swing")):
        for sub in Usd.PrimRange(prim):
            if sub.HasAPI(UsdPhysics.CollisionAPI) or sub.HasAPI(UsdPhysics.MeshCollisionAPI):
                UsdPhysics.MeshCollisionAPI.Apply(sub)
                attr = sub.GetAttribute("physics:approximation")
                if not attr or not attr.IsValid():
                    attr = sub.CreateAttribute("physics:approximation", Sdf.ValueTypeNames.Token)
                attr.Set("convexHull")
                count += 1
